import java.util.List;

class Node {
    public int val;
    public List<Node> children;

    public Node() {}

    public Node(int _val) {
        val = _val;
    }
}

public int maxDepth(Node root) {
    if (root == null) {
        return 0;
    }
    int depth = 0;
    for (Node child : root.children) {
        depth = Math.max(depth, maxDepth(child));
    }
    return 1 + depth;
}
```

